const input = $input.first().json;
const cbq = input.callback_query;
if (cbq) {
  return [{ json: {
    type: 'callback',
    chatId: cbq.message.chat.id,
    callbackId: cbq.id,
    data: cbq.data || '',
    isVoice: false, text: '', fileId: null,
    fileName: null, fileMime: null, fileSize: 0
  }}];
}
const msg = input.message;
if (!msg) return [];
const chatId = msg.chat.id;
const text = msg.text || msg.caption || '';
const isVoice = !!msg.voice;

// Document or photo detection
const isDoc = !!msg.document;
const isPhoto = !!(msg.photo && msg.photo.length);
if (isDoc) {
  return [{ json: {
    type: 'file', chatId, isVoice: false, text,
    fileId: msg.document.file_id,
    fileName: msg.document.file_name || 'document',
    fileMime: msg.document.mime_type || '',
    fileSize: msg.document.file_size || 0,
    fileType: 'document',
    callbackId: null, data: null
  }}];
}
if (isPhoto) {
  const best = msg.photo[msg.photo.length - 1];
  return [{ json: {
    type: 'file', chatId, isVoice: false, text,
    fileId: best.file_id,
    fileName: 'photo_' + Date.now() + '.jpg',
    fileMime: 'image/jpeg',
    fileSize: best.file_size || 0,
    fileType: 'photo',
    callbackId: null, data: null
  }}];
}

if (!isVoice && !text) return [];
const isStart = text === '/start' || text === '/menu';
const isAdmin = /^\/курсы|^\/добавить |^\/удалить |^\/промпт|^\/myid/i.test(text);
if (isAdmin) return [{ json: { type: 'admin', chatId, text, isVoice: false, fileId: null, fileName: null, fileMime: null, fileSize: 0, callbackId: null, data: null } }];
return [{ json: {
  type: isStart ? 'start' : (isVoice ? 'voice' : 'text'),
  chatId, isVoice, text,
  fileId: isVoice ? msg.voice.file_id : null,
  fileName: null, fileMime: null, fileSize: 0,
  callbackId: null, data: null
}}];

const { chatId, callbackId, data } = $input.first().json;
const [prefix, value] = (data || 'section:chat').split(':');
const section = value || 'chat';
const store = $getWorkflowStaticData('global');
if (!store.sessions) store.sessions = {};
store.sessions[String(chatId)] = { section, isAgent: prefix === 'agent' };
const names = {
  tasks:'📋 Задачи', notes:'📝 Заметки',
  sport:'🏋️ Спорт', work:'💼 Работа',
  ideas:'💡 Идеи', app:'🌐 Приложение',
  producer:'🎬 Продюсер', writer:'✍️ Сценарист',
  editor:'🎥 Монтажёр', sales:'💰 Продажник'
};
return [{ json: { chatId, callbackId, section, sectionName: names[section] || section } }];

const chatId = $('Router').item.json.chatId;
const text = $input.first().json?.text;
const hasText = typeof text === 'string' && text.trim().length > 0;
if (!hasText) {
  return [{ json: { chatId, userText: 'Ответь строго этой фразой: «🔱 Не разобрал голосовое, Денис. Перешли текстом, пожалуйста.» Больше ничего.', isVoice: true, systemPrompt: 'Ты только повторяешь заготовленную реплику. Никакого творчества.', _skipPrompt: true } }];
}
const store = $getWorkflowStaticData('global');
const section = store.sessions?.[String(chatId)]?.section || 'chat';
return [{ json: { chatId, userText: text, isVoice: true, channel: 'tg-voice', section } }];

const d = $input.first().json;
const store = $getWorkflowStaticData('global');
const session = store.sessions?.[String(d.chatId)] || {};
const section = session.section || 'chat';
return [{ json: { chatId: d.chatId, userText: d.text, isVoice: false, channel: 'tg-text', section } }];

const res = $input.first().json;
let text;
if (res?.choices?.[0]?.message?.content) {
  text = res.choices[0].message.content;
} else if (res?.error) {
  text = '🔱 Зевс задумался… попробуй через минуту, Денис.';
} else {
  text = '🔱 Зевс задумался… попробуй ещё раз, Денис.';
}
const chatId = $('Router').item.json.chatId;
const isVoice = $('Router').item.json.isVoice;
return [{ json: { chatId, text, isVoice } }];

const { chatId, text } = $input.first().json;
const store = $getWorkflowStaticData('global');
if (!store.siteConfig) store.siteConfig = {};
if (!store.siteConfig.courses) store.siteConfig.courses = [];

let reply = '';

// /курсы — show courses list
if (/^\/курсы/i.test(text)) {
  if (!store.siteConfig.courses.length) { reply = '📋 Курсов пока нет.'; }
  else { reply = '📋 *Курсы Студии ЧЕ:*\n\n' + store.siteConfig.courses.map((c,i) => `${i+1}. "${c.name}" — ${c.price}${c.level?' ('+c.level+')':''}`).join('\n'); }
}
// /добавить Название — 9990 ₽ (уровень)
else if (/^\/добавить /i.test(text)) {
  const raw = text.replace(/^\/добавить /i, '').trim();
  const m = raw.match(/^(.+?)\s*—\s*([\d\s]+[₽руб.]+.*)$/i);
  if (!m) { reply = '⚠️ Формат: /добавить Название курса — 9 990 ₽'; }
  else {
    const name = m[1].trim();
    const price = m[2].trim();
    store.siteConfig.courses.push({ name, price });
    reply = `✅ Добавлен курс:\n"${name}" — ${price}`;
  }
}
// /удалить Название
else if (/^\/удалить /i.test(text)) {
  const name = text.replace(/^\/удалить /i, '').trim().toLowerCase();
  const before = store.siteConfig.courses.length;
  store.siteConfig.courses = store.siteConfig.courses.filter(c => !c.name.toLowerCase().includes(name));
  const removed = before - store.siteConfig.courses.length;
  reply = removed ? `🗑 Удалено курсов: ${removed}` : '⚠️ Курс не найден. Проверь название.';
}
// /промпт — show base prompt
else if (/^\/промпт/i.test(text)) {
  const p = store.siteConfig.basePrompt || '(не задан)';
  reply = '📝 *Системный промпт бота:*\n\n' + p.slice(0, 3000);
}
// /myid — get telegram chat id
else if (/^\/myid/i.test(text)) {
  reply = '🆔 Твой chat id: ' + chatId;
}

return [{ json: { chatId, reply } }];

const ctx = $('Is File?').first().json;
const chatId = String(ctx.chatId);
const ts = Date.now();
const safeName = (ctx.fileName || 'file').replace(/[^a-zA-Z0-9а-яА-ЯёЁ._-]/g, '_');
// Flat structure: chatId prefix in filename (no subdirs)
const filePath = '/files/' + chatId + '_' + ts + '_' + safeName;

return [{
  json: {
    chatId: ctx.chatId,
    fileId: 'f_' + ts,
    fileName: ctx.fileName,
    fileType: ctx.fileType || 'document',
    fileMime: ctx.fileMime || '',
    fileSize: ctx.fileSize || 0,
    filePath: filePath,
    caption: ctx.text || '',
    ts: new Date().toISOString()
  },
  binary: $input.first().binary
}];

const uploadUrl = $json.href;
if (!uploadUrl) {
  throw new Error('No upload URL: ' + JSON.stringify($json));
}
const saved = $('Prep File Path').first().json;
return [{ json: { uploadUrl, filePath: saved.filePath, fileName: saved.fileName } }];

const f = $json.files[0];
const chatId = $('Build Reply').first().json.chatId;
return [{ json: { path: f.path, name: f.name, description: f.description || '', mime: f.mime || 'application/octet-stream', chatId } }];

const j = $input.first().json;
const userText = j.userText || '';
const chatId = String(j.chatId);
const isVoice = !!j.isVoice;
const baseSystem = j.systemPrompt || 'Ты Зевс — личный ассистент Дениса.';
const OPENAI_KEY = $env.OPENAI_API_KEY;
const PWA = 'https://mycheagent.ru/webhook/pwa-data';

const store = $getWorkflowStaticData('global');
if (!store.chatMem) store.chatMem = {};
if (!store.chatMem[chatId]) store.chatMem[chatId] = [];
const memory = (store.chatMem[chatId] || []).slice(-20);

const tools = [
  { type: 'function', function: { name: 'get_finance', description: 'Агрегаты доходов/расходов за месяц по Альфе. Возвращает totalIn, totalOut и разбивку по категориям.', parameters: { type: 'object', properties: { monthKey: { type: 'string', description: 'YYYY-MM, по умолчанию текущий месяц' } } } } },
  { type: 'function', function: { name: 'list_transactions', description: 'Список транзакций за месяц с фильтрами. Возвращает txId-ы которые потом можно передать в remove_transaction или set_category.', parameters: { type: 'object', properties: { monthKey: { type: 'string' }, category: { type: 'string', description: 'Категория для фильтра' }, direction: { type: 'string', enum: ['in','out'] }, search: { type: 'string', description: 'Поиск по purpose/recipient/sender' }, limit: { type: 'number', description: 'до 50, по умолчанию 10' } } } } },
  { type: 'function', function: { name: 'remove_transaction', description: 'Удалить транзакцию из учёта по id. Используй например когда пользователь говорит "не учитывай", "это перевод", "удали".', parameters: { type: 'object', properties: { txId: { type: 'string' } }, required: ['txId'] } } },
  { type: 'function', function: { name: 'set_category', description: 'Изменить категорию транзакции. По умолчанию запоминает мерчанта как правило для будущих транзакций.', parameters: { type: 'object', properties: { txId: { type: 'string' }, category: { type: 'string' }, rememberRule: { type: 'boolean' } }, required: ['txId','category'] } } },
  { type: 'function', function: { name: 'get_bubbles', description: 'Получить задачи и цели Дениса из Bubbleplan.', parameters: { type: 'object', properties: { activeOnly: { type: 'boolean', description: 'По умолчанию true' } } } } },
  { type: 'function', function: { name: 'direct_account_info', description: 'Информация об аккаунте Яндекс.Директ (логин, валюта, лимиты, доступные типы кампаний).', parameters: { type: 'object', properties: {} } } },
  { type: 'function', function: { name: 'direct_list_campaigns', description: 'Список рекламных кампаний в Директе. По умолчанию только активные/приостановленные (без архива).', parameters: { type: 'object', properties: { includeArchived: { type: 'boolean', description: 'По умолчанию false' }, limit: { type: 'number', description: 'до 100, по умолчанию 30' } } } } },
  { type: 'function', function: { name: 'direct_get_stats', description: 'Статистика по кампаниям из Reports API. Period: YESTERDAY (вчера), LAST_WEEK (прошлая неделя), LAST_30_DAYS (последние 30 дней), THIS_MONTH (текущий месяц), THIS_WEEK (текущая неделя), TODAY (сегодня), ALL_TIME (всё время). Можно фильтровать по campaignId.', parameters: { type: 'object', properties: { period: { type: 'string', enum: ['YESTERDAY','TODAY','LAST_WEEK','THIS_WEEK','LAST_30_DAYS','THIS_MONTH','ALL_TIME'] }, campaignId: { type: 'number', description: 'Опционально — статистика только по одной кампании' } } } } },
  { type: 'function', function: { name: 'direct_pause_campaign', description: 'Поставить кампанию на паузу. Требует явного намерения пользователя — не зови без прямой команды.', parameters: { type: 'object', properties: { campaignId: { type: 'number' } }, required: ['campaignId'] } } },
  { type: 'function', function: { name: 'direct_resume_campaign', description: 'Возобновить (запустить) кампанию. Требует явного подтверждения пользователя — деньги начнут списываться.', parameters: { type: 'object', properties: { campaignId: { type: 'number' } }, required: ['campaignId'] } } },
  { type: 'function', function: { name: 'direct_archive_campaign', description: 'Архивировать кампанию (необратимо переводит в архив, показов больше не будет).', parameters: { type: 'object', properties: { campaignId: { type: 'number' } }, required: ['campaignId'] } } }
];

const hint = '\n\nТы можешь выполнять действия через инструменты:\n— ФИНАНСЫ: get_finance, list_transactions, remove_transaction, set_category. На «не учитывай», «это перевод», «удали» — найди последнюю транзакцию (list_transactions limit:1, monthKey текущий) и удали её через remove_transaction.\n— ЗАДАЧИ: get_bubbles.\n— ДИРЕКТ: direct_account_info, direct_list_campaigns, direct_get_stats, direct_pause_campaign, direct_resume_campaign, direct_archive_campaign. ПРАВИЛО: pause/resume/archive — ТОЛЬКО при ЯВНОМ запросе пользователя («поставь на паузу», «запусти», «заархивируй»). Не вызывай эти tools по «своему усмотрению». Если просят «покажи статистику Директа» — направление period: вчерашний день по умолчанию.\nКогда отчитываешься — по-русски, кратко, без воды. Цифры округляй до целых.';
const CATS = ['Еда','Коммуналка','Топливо','Такси','Кредит','Отдых','Дети','Здоровье и спорт','Неожид','Покупки','Покурить','Подписки оплаты','ИИ, серверы, костыли'];
const hint2 = '\nКатегории трат: ' + CATS.join(', ') + '. Только эти 13.';

const messages = [
  { role: 'system', content: baseSystem + hint + hint2 },
  ...memory.map(m => ({ role: m.role, content: m.content })),
  { role: 'user', content: userText }
];

async function http(opt) { return await this.helpers.httpRequest.call(this.helpers, opt); }
const doHttp = (opt) => this.helpers.httpRequest(opt);

async function backendCall(action, payload) {
  return await doHttp({ method: 'POST', url: PWA, headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ action, ...(payload||{}) }), json: true, timeout: 15000 });
}

async function execTool(name, args) {
  args = args || {};
  const monthKey = args.monthKey || new Date().toISOString().slice(0,7);
  if (name === 'get_finance') {
    const r = await backendCall('getAlfaTx', { monthKey });
    const txs = r?.txs || [];
    const ins = txs.filter(t => t.direction === 'in');
    const outs = txs.filter(t => t.direction !== 'in');
    const totalIn = ins.reduce((s,t)=>s+(+t.amount||0),0);
    const totalOut = outs.reduce((s,t)=>s+(+t.amount||0),0);
    const byCategory = {};
    for (const t of outs) {
      const c = t.category || '⚠️ Без категории';
      byCategory[c] = (byCategory[c]||0) + (+t.amount||0);
    }
    return { monthKey, totalIn, totalOut, txCount: txs.length, byCategory };
  }
  if (name === 'list_transactions') {
    const r = await backendCall('getAlfaTx', { monthKey });
    let txs = r?.txs || [];
    if (args.category) txs = txs.filter(t => (t.category||'').toLowerCase().includes(String(args.category).toLowerCase()));
    if (args.direction) txs = txs.filter(t => t.direction === args.direction);
    if (args.search) {
      const s = String(args.search).toLowerCase();
      txs = txs.filter(t => (t.purpose||'').toLowerCase().includes(s) || (t.category||'').toLowerCase().includes(s) || (t.recipient||'').toLowerCase().includes(s) || (t.sender||'').toLowerCase().includes(s));
    }
    const limit = Math.min(args.limit || 10, 50);
    return { count: txs.length, txs: txs.slice(0, limit).map(t => ({ id: t.id, amount: t.amount, direction: t.direction, category: t.category, purpose: (t.purpose||'').slice(0,120), txDate: t.txDate, mcc: t.mcc, recipient: t.recipient, sender: t.sender })) };
  }
  if (name === 'remove_transaction') {
    return await backendCall('removeAlfaTx', { txId: args.txId });
  }
  if (name === 'set_category') {
    return await backendCall('setAlfaCategory', { txId: args.txId, category: args.category, rememberRule: args.rememberRule !== false });
  }
  if (name === 'get_bubbles') {
    const r = await backendCall('getBubbles', { activeOnly: args.activeOnly !== false });
    return { bubbles: (r?.bubbles||[]).slice(0, 30).map(b => ({ id: b.id, title: b.title, type: b.type, parent_id: b.parent_id, deadline: b.deadline })) };
  }

  // ── Direct API tools ──
  const DIRECT = 'https://mycheagent.ru/webhook/yadirect';
  const directCall = async (payload) => doHttp({ method: 'POST', url: DIRECT, headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload), json: true, timeout: 60000 });

  if (name === 'direct_account_info') {
    const r = await directCall({ action: 'clients.get' });
    if (!r?.ok) return { error: r?.error || r?.detail || 'direct error', code: r?.error_code };
    const c = r.result?.Clients?.[0] || {};
    const limits = {};
    for (const x of (c.Restrictions||[])) limits[x.Element] = x.Value;
    return { login: c.Login, clientId: c.ClientId, currency: c.Currency, vatRate: c.VatRate, productMode: c.ProductMode, availableCampaignTypes: c.AvailableCampaignTypes, limits, units: r.units };
  }
  if (name === 'direct_list_campaigns') {
    const r = await directCall({ action: 'campaigns.get' });
    if (!r?.ok) return { error: r?.error || 'direct error', code: r?.error_code };
    let camps = r.result?.Campaigns || [];
    if (!args.includeArchived) camps = camps.filter(c => c.State !== 'ARCHIVED');
    const limit = Math.min(args.limit || 30, 100);
    return { count: camps.length, campaigns: camps.slice(0, limit).map(c => ({ id: c.Id, name: c.Name, type: c.Type, status: c.Status, state: c.State, startDate: c.StartDate, dailyBudget: c.DailyBudget, currency: c.Currency, spent: (c.Funds?.SharedAccountFunds?.Spend||0)/1000000 })) };
  }
  if (name === 'direct_get_stats') {
    const period = args.period || 'YESTERDAY';
    const reportBody = { params: { SelectionCriteria: args.campaignId ? { Filter: [{ Field: 'CampaignId', Operator: 'EQUALS', Values: [String(args.campaignId)] }] } : {}, FieldNames: ['Date','CampaignId','CampaignName','Impressions','Clicks','Ctr','Cost','AvgCpc','Conversions','CostPerConversion'], ReportName: 'agent_' + Date.now(), ReportType: 'CAMPAIGN_PERFORMANCE_REPORT', DateRangeType: period, Format: 'TSV', IncludeVAT: 'YES', IncludeDiscount: 'NO' } };
    const r = await directCall({ action: 'reports.get', body: reportBody });
    if (!r?.ok) return { error: r?.error || 'direct error', code: r?.error_code };
    const text = (typeof r.result === 'string' ? r.result : (r.raw || ''));
    if (!text || text.length < 30) return { period, info: 'Нет данных за период', rawSize: text.length };
    const lines = text.split(/\r?\n/).filter(l => l.trim() && !l.startsWith('Total'));
    if (lines.length < 2) return { period, info: 'Нет данных', sample: text.slice(0, 200) };
    const header = lines[0].split('\t');
    const rows = lines.slice(1).map(l => { const c = l.split('\t'); const o = {}; header.forEach((h,i)=>o[h]=c[i]); return o; });
    let totImp = 0, totClk = 0, totCost = 0, totConv = 0;
    for (const row of rows) { totImp += +row.Impressions || 0; totClk += +row.Clicks || 0; totCost += (+row.Cost || 0)/1000000; totConv += +row.Conversions || 0; }
    return { period, totals: { impressions: totImp, clicks: totClk, cost: Math.round(totCost), conversions: totConv, ctr: totImp ? +(totClk/totImp*100).toFixed(2) : 0, cpc: totClk ? Math.round(totCost/totClk) : 0 }, rowsCount: rows.length, rows: rows.slice(0, 30) };
  }
  if (name === 'direct_pause_campaign') {
    if (!args.campaignId) return { error: 'campaignId required' };
    return await directCall({ action: 'campaigns.suspend', ids: [args.campaignId] });
  }
  if (name === 'direct_resume_campaign') {
    if (!args.campaignId) return { error: 'campaignId required' };
    return await directCall({ action: 'campaigns.resume', ids: [args.campaignId] });
  }
  if (name === 'direct_archive_campaign') {
    if (!args.campaignId) return { error: 'campaignId required' };
    return await directCall({ action: 'campaigns.archive', ids: [args.campaignId] });
  }

  return { error: 'unknown tool: ' + name };
}

let finalReply = null;
for (let iter = 0; iter < 6; iter++) {
  let res;
  try {
    res = await doHttp({ method: 'POST', url: 'https://api.openai.com/v1/chat/completions', headers: { Authorization: 'Bearer ' + OPENAI_KEY, 'Content-Type': 'application/json' }, body: JSON.stringify({ model: 'gpt-4o-mini', messages, tools, tool_choice: 'auto', max_tokens: 800 }), json: true, timeout: 60000 });
  } catch (e) {
    finalReply = '⚠️ Ошибка GPT: ' + (e.message || e).toString().slice(0, 200);
    break;
  }
  const message = res?.choices?.[0]?.message;
  if (!message) { finalReply = '⚠️ Не получилось обратиться к GPT'; break; }
  messages.push(message);
  if (!message.tool_calls || !message.tool_calls.length) {
    finalReply = (message.content || '').trim() || '(пустой ответ)';
    break;
  }
  for (const tc of message.tool_calls) {
    let result;
    try {
      const args = JSON.parse(tc.function.arguments || '{}');
      result = await execTool(tc.function.name, args);
    } catch (e) {
      result = { error: String(e.message || e) };
    }
    messages.push({ role: 'tool', tool_call_id: tc.id, content: JSON.stringify(result).slice(0, 8000) });
  }
}
if (!finalReply) finalReply = '⚠️ Слишком много шагов — не закончил';

store.chatMem[chatId].push({ role: 'user', content: userText });
store.chatMem[chatId].push({ role: 'assistant', content: finalReply });
if (store.chatMem[chatId].length > 30) store.chatMem[chatId] = store.chatMem[chatId].slice(-30);

return [{ json: { chatId, text: finalReply, isVoice } }];

const j = $input.first().json;
const m = (j.data || '').match(/^fincat:([^:]+):(\d+)$/);
if (!m) return [];
const cats = ['Еда','Коммуналка','Топливо','Такси','Кредит','Отдых','Дети','Здоровье и спорт','Неожид','Покупки','Покурить','Подписки оплаты','ИИ, серверы, костыли'];
const idx = parseInt(m[2]);
const category = cats[idx] || null;
return [{ json: { txId: m[1], category, chatId: j.chatId, callbackId: j.callbackId } }];
